               {aiPopulatedFields.size > 0 && (
                 <div className="text-[10px] text-indigo-600 font-medium flex items-center gap-1.5">
                    <CheckCircle2 className="w-3 h-3" />
                    Successfully updated {aiPopulatedFields.size} fields from {selectedReportId ? reportDocs.find(d => d.id === selectedReportId)?.name : reportDocs[0]?.name}
