}

export interface AiSuggestion {
  id: string;
  docId: string;
  type: 'QUANTITY_UPDATE' | 'BILL_DETECTION' | 'RISK_ALERT' | 'BOQ_IMPORT';
  title: string;
  description: string;
  value?: any; // Quantity number or Bill object or BOQItem[]
