    The workDoneQty should be a realistic daily number for that type of task.
    If the document title mentions a date or specific task, use that.

    Return JSON with fields: date, activity, location, laborCount, remarks, workDoneQty, linkedBoqId.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            date: { type: Type.STRING },
            activity: { type: Type.STRING },
            location: { type: Type.STRING },
            laborCount: { type: Type.NUMBER },
            remarks: { type: Type.STRING },
            workDoneQty: { type: Type.NUMBER },
            linkedBoqId: { type: Type.STRING }
          }
        }
      }
    });
    return JSON.parse(response.text || "null");
  } catch (error) {
    console.error("DPR Extraction error:", error);
    return null;
  }
};

