                                 </button>
                               )}
                            </div>

                            {hasBreakdown ? (
                              <div className="grid grid-cols-4 gap-6 text-center">
                                <div className="space-y-1">
                                  <p className="text-[10px] font-bold text-slate-400 uppercase">Material</p>
                                  <p className="text-lg font-mono font-bold text-slate-800">৳{item.costAnalysis?.breakdown.material.toLocaleString()}</p>
                                  <div className="w-full h-1 bg-slate-100 rounded-full overflow-hidden">
                                    <div className="h-full bg-blue-500" style={{ width: `${(item.costAnalysis?.breakdown.material || 0) / actualCost * 100}%` }}></div>
                                  </div>
                                </div>
                                <div className="space-y-1">
                                  <p className="text-[10px] font-bold text-slate-400 uppercase">Labor</p>
                                  <p className="text-lg font-mono font-bold text-slate-800">৳{item.costAnalysis?.breakdown.labor.toLocaleString()}</p>
                                  <div className="w-full h-1 bg-slate-100 rounded-full overflow-hidden">
                                    <div className="h-full bg-amber-500" style={{ width: `${(item.costAnalysis?.breakdown.labor || 0) / actualCost * 100}%` }}></div>
                                  </div>
                                </div>
                                <div className="space-y-1">
                                  <p className="text-[10px] font-bold text-slate-400 uppercase">Equipment</p>
                                  <p className="text-lg font-mono font-bold text-slate-800">৳{item.costAnalysis?.breakdown.equipment.toLocaleString()}</p>
                                  <div className="w-full h-1 bg-slate-100 rounded-full overflow-hidden">
                                    <div className="h-full bg-emerald-500" style={{ width: `${(item.costAnalysis?.breakdown.equipment || 0) / actualCost * 100}%` }}></div>
                                  </div>
                                </div>
                                <div className="space-y-1">
                                  <p className="text-[10px] font-bold text-slate-400 uppercase">Overhead</p>
                                  <p className="text-lg font-mono font-bold text-slate-800">৳{item.costAnalysis?.breakdown.overhead.toLocaleString()}</p>
                                  <div className="w-full h-1 bg-slate-100 rounded-full overflow-hidden">
                                    <div className="h-full bg-violet-500" style={{ width: `${(item.costAnalysis?.breakdown.overhead || 0) / actualCost * 100}%` }}></div>
                                  </div>
                                </div>
                              </div>
                            ) : (
                              <div className="py-4 text-center text-slate-400 text-xs flex flex-col items-center gap-2">
                                <Lock className="w-4 h-4 opacity-20" />
                                <p>No detailed breakdown available for actual cost.</p>
                                <p className="text-[10px]">Use "AI Suggest" to decompose the total ৳{actualCost} based on planned metrics.</p>
                              </div>
                            )}
                          </div>
                        </td>
                      </tr>
                    )}
                  </React.Fragment>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 min-h-[400px]">
        <BillTable bills={clientBills} title="Client RA Bills" />
        <BillTable bills={vendorBills} title="Vendor Invoices (Payables)" />
      </div>

      {isBillModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 p-4 backdrop-blur-sm">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
            <div className="px-6 py-4 border-b border-slate-200 flex justify-between items-center bg-slate-50">
              <div className="flex items-center gap-2">
                <h3 className="font-semibold text-slate-800">
                  {billType === 'CLIENT_RA' ? 'Record Bill Received (PE)' : 'Add Expense / Invoice'}
                </h3>
                {aiAutofilled && (
                  <div className="flex items-center gap-1.5 px-2 py-0.5 bg-emerald-50 text-emerald-600 text-[10px] font-bold rounded animate-pulse">
                    <CheckCircle2 className="w-3 h-3" />
                    AI Auto-Filled
                  </div>
                )}
              </div>
              <button onClick={() => setIsBillModalOpen(false)}><X className="w-5 h-5 text-slate-400"/></button>
            </div>
            <form onSubmit={handleCreateBill} className="p-6 space-y-4">
               {billType !== 'CLIENT_RA' && (
                 <div>
                   <label className="block text-sm font-medium text-slate-700 mb-1">Expense Type</label>
                   <select 
                     value={billType} 
                     onChange={(e) => setBillType(e.target.value as any)}
                     className="w-full px-3 py-2 border border-slate-300 rounded-lg text-sm bg-white"
                   >
                     <option value="VENDOR_INVOICE">General Vendor Invoice</option>
                     <option value="MATERIAL_EXPENSE">Material Purchase</option>
                     <option value="SUB_CONTRACTOR">Sub-Contractor Bill</option>
                   </select>
                 </div>
               )}
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-1">
                    Entity Name
                    {aiAutofilled && <Sparkles className="w-2.5 h-2.5 text-emerald-500" />}
                  </label>
                  <input 
                    type="text" 
                    required 
                    value={billEntity} 
                    onChange={(e) => setBillEntity(e.target.value)}
                    placeholder="e.g. ABC Constructions Ltd."
                    className={`w-full px-3 py-2 border rounded-lg text-sm transition-all ${aiAutofilled ? 'border-emerald-200 bg-emerald-50/20' : 'border-slate-300'}`}
                  />
               </div>
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-1">
                    Amount (৳)
                    {aiAutofilled && <Sparkles className="w-2.5 h-2.5 text-emerald-500" />}
                  </label>
                  <input 
                    type="number" 
                    required 
                    min="0"
                    step="0.01"
                    value={billAmount} 
                    onChange={(e) => setBillAmount(e.target.value)}
                    className={`w-full px-3 py-2 border rounded-lg text-sm transition-all ${aiAutofilled ? 'border-emerald-200 bg-emerald-50/20' : 'border-slate-300'}`}
                  />
               </div>
               <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1 flex items-center gap-1">
                    Date
                    {aiAutofilled && <Sparkles className="w-2.5 h-2.5 text-emerald-500" />}
                  </label>
                  <input 
                    type="date" 
                    required 
                    value={billDate} 
                    onChange={(e) => setBillDate(e.target.value)}
                    className={`w-full px-3 py-2 border rounded-lg text-sm transition-all ${aiAutofilled ? 'border-emerald-200 bg-emerald-50/20' : 'border-slate-300'}`}
                  />
               </div>

               {billType === 'CLIENT_RA' && detectedBillDocName && (
                 <div className="p-3 bg-blue-50 border border-blue-200 rounded-lg">
                   <p className="text-xs text-blue-700">
                     <strong>AI Action:</strong> Upon saving, the system will read <em>"{detectedBillDocName}"</em> to automatically distribute the billed amount to individual BOQ items.
                   </p>
                 </div>
               )}

               <button type="submit" className="w-full bg-blue-600 text-white py-2 rounded-lg font-bold hover:bg-blue-700">
                 Save Record {billType === 'CLIENT_RA' && detectedBillDocName ? '& Auto-Distribute' : ''}
               </button>
            </form>
          </div>
        </div>
      )}

      <DocumentManager 
        documents={data.documents} 
        onAddDocument={onAddDocument} 
        onBillUploaded={handleBillUploaded}
        filterModule="FINANCE" 
        compact={true}
        allowUpload={canUploadDoc}
      />
    </div>
  );
};

export default FinancialControl;

export enum Unit {
  SQM = 'SQM',
  CUM = 'CUM',
  KG = 'KG',
  NOS = 'NOS',
  RMT = 'RMT',
  CFT = 'CFT',
  BAG = 'BAG',
  TON = 'TON'
}

export type UserRole = 'DIRECTOR' | 'MANAGER' | 'ACCOUNTANT' | 'ENGINEER';
export type Priority = 'LOW' | 'MEDIUM' | 'HIGH';

export interface User {
  name: string;
  role: UserRole;
  avatar?: string;
}

export interface CostBreakdown {
  material: number;
  labor: number;
  equipment: number;
  overhead: number;
}

export interface CostAnalysis {
  unitCost: number; // Actual cost per unit
  breakdown: CostBreakdown;
}

export interface BOQItem {
  id: string;
  description: string;
  unit: Unit;
  rate: number; // Contract Selling Rate
  plannedQty: number;
  plannedUnitCost: number; // Internal Budgeted Cost
  plannedBreakdown?: CostBreakdown; // Detailed planned breakdown
  executedQty: number; // From Site Execution
  billedAmount?: number; // Cumulative amount certified/received from PE
  costAnalysis?: CostAnalysis;
  priority?: Priority;
}

export interface MaterialConsumption {
  materialId: string;
  qty: number;
}

export interface SubContractor {
  id: string;
  name: string;
  specialization: string;
  contactNumber?: string;
  agreedRates: { boqId: string; rate: number }[]; // Rate per unit for specific BOQ items
  totalWorkValue: number; // Value of work done based on DPRs
  totalBilled: number; // Amount billed/paid via Bills
  currentLiability: number; // totalWorkValue - totalBilled
  pdRemarks?: string;
}

export interface DPR {
  id: string;
  date: string;
  activity: string;
  location: string;
  laborCount: number;
  remarks: string;
  linkedBoqId?: string; // Optional link to BOQ
  subContractorId?: string; // Link to Sub-Contractor if they did the work
  workDoneQty?: number; // Quantity achieved today
  materialsUsed?: MaterialConsumption[]; // Materials consumed in this activity
  pdRemarks?: string; // Project Director Note
}

export interface Material {
  id: string;
  name: string;
  unit: Unit;
  totalReceived: number; // Cumulative Sent to Site
  totalConsumed: number; // Cumulative Used
  currentStock: number; // Calculated Stock
  averageRate: number; // Buying Price per unit
  pdRemarks?: string; // Project Director Note
}

export interface Bill {
  id: string;
  type: 'CLIENT_RA' | 'VENDOR_INVOICE' | 'SUB_CONTRACTOR' | 'MATERIAL_EXPENSE';
  entityName: string; // Client or Vendor Name
  amount: number;
  date: string;
  status: 'PAID' | 'PENDING';
  pdRemarks?: string;
}

export interface Liability {
  id: string;
  description: string;
  type: 'RETENTION' | 'PENDING_PO' | 'UNBILLED_WORK';
  amount: number;
  dueDate: string;
}

export interface Milestone {
  id: string;
  title: string;
  date: string;
  status: 'COMPLETED' | 'PENDING' | 'AT_RISK';
  description?: string;
}

export type DocumentCategory = 'CONTRACT' | 'DRAWING' | 'PERMIT' | 'REPORT' | 'BILL' | 'OTHER';
export type ModuleType = 'MASTER' | 'SITE' | 'FINANCE' | 'LIABILITY' | 'GENERAL';

export interface ProjectDocument {
  id: string;
  name: string;
  type: string; // e.g., 'PDF', 'JPG', 'XLSX'
  category: DocumentCategory;
  module: ModuleType;
  uploadDate: string;
  size: string;
  url?: string;
  isAnalyzed?: boolean;
}

export interface AiSuggestion {
  id: string;
  docId: string;
  type: 'QUANTITY_UPDATE' | 'BILL_DETECTION' | 'RISK_ALERT' | 'BOQ_IMPORT';
  title: string;
  description: string;
  value?: any; // Quantity number or Bill object or BOQItem[]
  linkedId?: string; // BOQ Item ID or similar
  status: 'PENDING' | 'APPLIED' | 'DISMISSED';
}

export interface ProjectState {
  id: string;
  name: string;
  status: 'ACTIVE' | 'COMPLETED' | 'ON_HOLD';
  priority: Priority;
  contractValue: number;
  startDate: string;
  endDate: string;
  boq: BOQItem[];
  materials: Material[]; // New Material Inventory
  subContractors: SubContractor[]; // New Sub-Contractor Management
  dprs: DPR[];
  bills: Bill[];
  liabilities: Liability[];
  milestones: Milestone[];
  documents: ProjectDocument[];
  aiSuggestions: AiSuggestion[];
}

export interface ExtractedDPR {
  date?: string;
  activity?: string;
  location?: string;
  laborCount?: number;
  remarks?: string;
  workDoneQty?: number;
  linkedBoqId?: string;
  subContractorName?: string; // AI detected name
  materialUsageText?: string; // AI detected material text to parse
}

export interface ExtractedBill {
  entityName?: string;
  amount?: number;
  date?: string;
  type?: 'CLIENT_RA' | 'VENDOR_INVOICE';
}

import { GoogleGenAI, Type } from "@google/genai";
import { ProjectState, ExtractedDPR, ExtractedBill, BOQItem, AiSuggestion, CostBreakdown, DocumentCategory, ModuleType } from "../types";

// Always use new GoogleGenAI({ apiKey: process.env.API_KEY }) inside functions for fresh instance
export const generateProjectInsights = async (projectData: ProjectState): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Calculate pending work high level stats
  const pendingItems = projectData.boq.filter(i => i.executedQty < i.plannedQty && i.priority === 'HIGH');

  const prompt = `
    Analyze the following construction project and provide a "Key Points & Progress Pending" report.

    Project Name: ${projectData.name}
    Contract Value: ${projectData.contractValue}

    Milestones:
    ${projectData.milestones.map(m => `- ${m.title} (${m.date}): ${m.status}`).join('\n')}

    Critical Pending BOQ Items (High Priority & Incomplete):
    ${pendingItems.slice(0, 5).map(i => `- ${i.description}: ${(i.executedQty/i.plannedQty*100).toFixed(1)}% complete. Remaining: ${i.plannedQty - i.executedQty} ${i.unit}`).join('\n')}

    Financials:
    - Bills: ${projectData.bills.length} records
    - Liabilities: ${projectData.liabilities.length} records.

    Please provide an executive summary formatted in Markdown with these sections:
    1. **Project Health**: Score (0-100%) and brief status.
    2. **Critical Pending Actions**: Identify the top 3 most urgent tasks based on High Priority BOQ items that are behind schedule.
    3. **Milestone Risk**: Comment on upcoming milestones and if the current rate of progress puts them at risk.
    4. **Recommendation**: One strategic move for the Project Director.

    Keep it professional, concise, and action-oriented.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "No insights generated.";
  } catch (error) {
    console.error("Error generating insights:", error);
    return "Failed to generate insights. Please check API configuration.";
  }
};

